import{_ as a,o as n,c as e,ae as t}from"./chunks/framework.BrB6tjxY.js";const k=JSON.parse('{"title":"Guide","description":"","frontmatter":{},"headers":[],"relativePath":"guide.md","filePath":"guide.md"}'),i={name:"guide.md"};function p(d,s,o,l,r,h){return n(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="guide" tabindex="-1">Guide <a class="header-anchor" href="#guide" aria-label="Permalink to &quot;Guide&quot;">​</a></h1><p><code>api-drift-agent</code> is a LangGraph-powered agentic workflow that detects breaking API changes in provider PRs, scans a configured list of consumer repos, and automatically opens GitHub Issues in any that are affected.</p><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Provider PR opened</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       ▼</span></span>
<span class="line"><span>┌─────────────────────────────────────┐</span></span>
<span class="line"><span>│  Download drift-guard-engine binary │</span></span>
<span class="line"><span>│  Auto-detect schema type &amp; compare  │</span></span>
<span class="line"><span>│  (OpenAPI, GraphQL, or gRPC/proto)  │</span></span>
<span class="line"><span>└─────────────────────────────────────┘</span></span>
<span class="line"><span>       │ breaking changes found</span></span>
<span class="line"><span>       ▼</span></span>
<span class="line"><span>┌─────────────────────────────────────┐</span></span>
<span class="line"><span>│  Scan consumer repos from           │</span></span>
<span class="line"><span>│  consumer-repos input               │</span></span>
<span class="line"><span>│  (no consumer-repos → post comment  │</span></span>
<span class="line"><span>│   with setup instructions &amp; skip)   │</span></span>
<span class="line"><span>└─────────────────────────────────────┘</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       ▼</span></span>
<span class="line"><span>┌─────────────────────────────────────┐</span></span>
<span class="line"><span>│  Clone each consumer repo           │</span></span>
<span class="line"><span>│  Scan for affected files            │</span></span>
<span class="line"><span>│  Open (or update) a GitHub Issue    │</span></span>
<span class="line"><span>│  Post DriftAgent Report on PR       │</span></span>
<span class="line"><span>└─────────────────────────────────────┘</span></span>
<span class="line"><span>       │ PR re-run / changes fixed</span></span>
<span class="line"><span>       ▼</span></span>
<span class="line"><span>┌─────────────────────────────────────┐</span></span>
<span class="line"><span>│  Close resolved consumer issues     │</span></span>
<span class="line"><span>│  Update PR comment → all clear ✅   │</span></span>
<span class="line"><span>└─────────────────────────────────────┘</span></span></code></pre></div><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Create a GitHub Personal Access Token (PAT) with <code>repo</code> and <code>read:org</code> scopes. This is required to clone and open issues in consumer repos. Add it as a repository secret named <code>ORG_READ_TOKEN</code> (<strong>Settings → Secrets and variables → Actions → New repository secret</strong>).</li><li>Optionally, add an <code>ANTHROPIC_API_KEY</code> secret to enable Claude-powered risk analysis in the issues the agent opens.</li></ul><h2 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h2><p>Add to your <strong>provider</strong> repo&#39;s workflow:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">API Drift Check</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">on</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  pull_request</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">permissions</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  contents</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">read</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  issues</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">write</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">jobs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  drift</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    runs-on</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ubuntu-latest</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    steps</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      - </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">uses</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">actions/checkout@v4</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">        with</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">          fetch-depth</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      - </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">uses</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">DriftAgent/api-drift-agent@v1</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">        with</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">          org-read-token</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">\${{ secrets.ORG_READ_TOKEN }}</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">          consumer-repos</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">            your-org/service-a</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">            your-org/service-b</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # anthropic-api-key: \${{ secrets.ANTHROPIC_API_KEY }}  # optional: enables AI risk analysis</span></span></code></pre></div><h2 id="inputs" tabindex="-1">Inputs <a class="header-anchor" href="#inputs" aria-label="Permalink to &quot;Inputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Input</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>base-schema</code></td><td>No</td><td>Path to schema file (auto-detected if omitted). Supports OpenAPI (<code>.yaml</code>/<code>.yml</code>/<code>.json</code>), GraphQL (<code>.graphql</code>/<code>.gql</code>), and Protobuf (<code>.proto</code>).</td></tr><tr><td><code>head-schema</code></td><td>No</td><td>Path on PR branch (defaults to <code>base-schema</code>)</td></tr><tr><td><code>org-read-token</code></td><td>No</td><td>PAT with <code>repo</code> + <code>read:org</code> scopes. Required to clone consumer repos and open issues in them. Falls back to <code>GITHUB_TOKEN</code> (cannot open issues in other repos).</td></tr><tr><td><code>consumer-repos</code></td><td>No</td><td>Newline or comma-separated list of consumer repos to scan (e.g. <code>org/repo</code>). When omitted, no scan is conducted and the PR comment will include setup instructions.</td></tr><tr><td><code>anthropic-api-key</code></td><td>No</td><td>Enables Claude risk analysis in opened issues</td></tr></tbody></table><h2 id="re-run-behaviour" tabindex="-1">Re-run behaviour <a class="header-anchor" href="#re-run-behaviour" aria-label="Permalink to &quot;Re-run behaviour&quot;">​</a></h2><p>The agent is fully idempotent across CI rebuilds:</p><table tabindex="0"><thead><tr><th>Scenario</th><th>PR comment</th><th>Consumer issues</th></tr></thead><tbody><tr><td>Re-run, same breaking changes</td><td>Updated in-place</td><td>Updated in-place — no duplicates</td></tr><tr><td>Re-run, more breaking changes</td><td>Updated in-place</td><td>Updated in-place</td></tr><tr><td>PR fixed — breaking changes gone</td><td>Updated → ✅ all clear</td><td>Closed with &quot;Breaking changes resolved&quot;</td></tr><tr><td>Breaking changes found, no <code>consumer-repos</code> configured</td><td>Posted with breaking changes table + setup instructions</td><td>Nothing touched</td></tr><tr><td>Clean PR, no previous activity</td><td>Nothing posted</td><td>Nothing touched</td></tr></tbody></table><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Symptom</th><th>Cause</th><th>Fix</th></tr></thead><tbody><tr><td>Action fails: &quot;No API schema found&quot;</td><td>Schema file not at a standard path, or generated at runtime and not committed</td><td>Set the <code>base-schema</code> input explicitly</td></tr><tr><td>Action fails: &quot;drift-guard-engine failed to diff schemas&quot;</td><td>Schema file is invalid or malformed</td><td>Validate locally: <code>drift-guard openapi --base ... --head ...</code> (or <code>graphql</code>/<code>grpc</code>)</td></tr><tr><td>Issues created but no AI explanations</td><td><code>ANTHROPIC_API_KEY</code> not set</td><td>Set the secret in your repo — the agent runs without it but skips Claude risk analysis</td></tr><tr><td>No issues created in consumer repos</td><td><code>org-read-token</code> not set, or PAT has insufficient scope</td><td>Set <code>org-read-token</code> to a PAT with <code>repo</code> + <code>read:org</code> scopes</td></tr><tr><td>PR comment shows &quot;no consumer scan conducted&quot;</td><td><code>consumer-repos</code> input not set</td><td>Add the <code>consumer-repos</code> input listing repos to scan</td></tr></tbody></table>`,16)])])}const u=a(i,[["render",p]]);export{k as __pageData,u as default};
